// ─────────────────────────────────────────────
// Monta URL do VHSYS com data BRT correta.
// CRÍTICO: type = 'entrada'/'saida' (lowercase) para o banco
//          Tipo = 'Entrada'/'Saida' (capitalizado) para a URL do VHSYS
// ─────────────────────────────────────────────
const row          = $input.first().json;
const ccId         = row.cc_id;
const entryRunned  = parseInt(row.entries_runned);
const outputRunned = parseInt(row.outputs_runned);

// Data atual em BRT (America/Sao_Paulo)
const now = new Date();
const brtOffset = -3 * 60; // UTC-3 em minutos
const brtDate   = new Date(now.getTime() + (now.getTimezoneOffset() + brtOffset) * 60000);
const day   = String(brtDate.getDate()).padStart(2, '0');
const month = String(brtDate.getMonth() + 1).padStart(2, '0');
const year  = brtDate.getFullYear();
const currentDate = `${day}/${month}/${year}`;

// Determina tipo — prioridade: entrada antes de saida
let type, urlTipo;
if (entryRunned === 0) {
  type    = 'entrada';
  urlTipo = 'Entrada';
} else {
  type    = 'saida';
  urlTipo = 'Saida';
}

const url = `https://app.vhsys.com.br/Relatorio/Relatorio.CentroCustos.JSON.php?considerarData=pagamento&Data1=01/01/2002&Data2=${currentDate}&ListarCentroAtivoSemLancamento=1&modelo=2&Nome=&Cod=&Tipo=${urlTipo}&Centro=${ccId}&Categoria=null&buscar=1`;

console.log(JSON.stringify({
  timestamp      : new Date().toISOString(),
  route          : 'cc_report_manage/next_url',
  event          : 'cc_next_url_generated',
  cc_id          : ccId,
  type           : type,
  date_brt       : currentDate,
  entries_runned : entryRunned,
  outputs_runned : outputRunned,
  level          : 'info'
}));

// statusCode 201 — preserva compatibilidade com Flask original
return {
  statusCode: 201,
  body: { url, cc_id: ccId, type }
};

// Nenhum CC pendente — tudo processado
console.log(JSON.stringify({
  timestamp : new Date().toISOString(),
  route     : 'cc_report_manage/next_url',
  event     : 'cc_next_url_no_pending',
  level     : 'info'
}));

return {
  statusCode: 201,
  body: { url: null, cc_id: null, type: null, message: 'No pending CCs found' }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp : new Date().toISOString(),
  route     : 'cc_report_manage/next_url',
  event     : 'db_error',
  message   : errData.message || 'Unknown DB error',
  level     : 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not fetch next CC URL' }
};
